head.script:
scwin.flag = false;
scwin.editFlag = false;
scwin.columnNum = 17;

scwin.onpageload = async function() {
    dma_searchCloseYm.set("coCd", "000");
    await $c.sbm.execute(sbm_getMaxCloseYm);
};

scwin.sbm_getMaxCloseYm_submitdone = function(e) {
};

scwin.sbm_getMaxCloseYm_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_CheckFileExt = function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext == path.substring((flen - elen), flen));
};

scwin.f_JobCloseYn = function(date) {
    date = date.substr(0, 6);
    if (ds_getMaxCloseYm.getCellData(0, "closeYm") > date) {
        return -1;
    }
    else if (ds_getMaxCloseYm.getCellData(0, "closeYm") < date) {
        return 0;
    }
    else {
        return 1;
    }
};

scwin.f_CsvValidation = async function() {
    if (ds_csv.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return false;
    }

    if (ds_csv.getColumnCount() != scwin.columnNum) {
        await $c.gus.cfAlertMsg("\n컬럼값이 상이합니다. [형식=" + scwin.columnNum + "개] 입력한 열 개수 => " + ds_csv.getColumnCount() + "\n업로드 양식을 다운로드후, 양식에 맞게 입력해주세요.");
        return false;
    }

    let cntRow = ds_csv.getRowCount();

    for (let i = 0; i < ds_csv.getRowCount(); i++) {
        let colcnt = 0;
        for (let v = 0; v < ds_csv.getColumnCount(); v++) {
            if (ds_csv.getCellData(i, ds_csv.getColumnID(v)) == null || ds_csv.getCellData(i, ds_csv.getColumnID(v)) == '') {
                colcnt += 1;
            }
        }
        if (colcnt == scwin.columnNum) {
            cntRow = i;
            break;
        }

        let err = "";
        let partner = '';
        partner = 'Y';
        ds_csv.setCellData(i, ds_csv.getColumnID(2), 'Y');

        let partnerYn = 'Y';

        ds_csv.setCellData(i, ds_csv.getColumnID(3), 'D');

        let customerCode = '';
        customerCode = ds_csv.getCellData(i, ds_csv.getColumnID(5));
        if (customerCode == null) {
            customerCode = '';
            ds_csv.setCellData(i, ds_csv.getColumnID(5), '');
        }

        customerCode = customerCode.replace(/ /gi, "");

        for (let k = 0; k < ds_csv.getColumnCount(); k++) {
            let temp = '';
            temp = ds_csv.getCellData(i, ds_csv.getColumnID(k));
            if (temp == null) {
                ds_csv.setCellData(i, ds_csv.getColumnID(k), '');
                temp = '';
            }
            temp = temp.replace(/ /gi, "");
            temp = temp.replace(/,/gi, "");
            temp = temp.toUpperCase();
            ds_csv.setCellData(i, ds_csv.getColumnID(k), temp);

            switch (k) {
            case 0:
                if (temp == '' || !(/^[SA]{1}$/.test(temp))) {
                    err += "'SEA/AIR'열에는 S나 A를 입력해주세요. ";
                }
                break;
            case 1:
                if (temp == '' || !(/^[IE]{1}$/.test(temp))) {
                    err += "'EXP/IMP'열에는 I나 E를 입력해주세요. ";
                }
                break;
            case 2:
                break;
            case 3:
                break;
            case 4:
                if (temp == '') {
                    err += "House B/L을 입력해주세요. ";
                }
                break;
            case 5:
                if (temp == '') {
                    err += "Customer Code를 입력해주세요. ";
                }
                break;
            case 6:
                if (temp == '') {
                    err += "Freight Code를 입력해주세요. ";
                }
                else if (partnerYn != 'Y' && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != ''
                        && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != 'KRW' && (ds_csv.getCellData(i, ds_csv.getColumnID(14)) == 'Y')) {
                    let c = temp.charAt(temp.length - 1);
                    if (c == 'J' || c == 'V' || c == 'K') {
                        err += "CUR이 KRW가 아니며 외화정산이 Y일 경우, 운임코드에 -J, -V, -K의 코드는 올 수 없습니다. ";
                    }
                }
                break;
            case 7:
                if (temp == '') {
                    err += "CUR를 입력해주세요. ";
                }
                break;
            case 8:
                if (isNaN(temp)) {
                    err += "'Amount'열은 숫자나 공백으로 입력해주세요. ";
                }
                break;
            case 9:
                if (isNaN(temp)) {
                    err += "'Ex-rate'열은 숫자나 공백으로 입력해주세요. ";
                }
                break;
            case 10:
                if (isNaN(temp)) {
                    err += "'Amount(원)'열은 숫자나 공백으로 입력해주세요. ";
                }
                break;
            case 11:
                if (isNaN(temp)) {
                    err += "'VAT'열은 숫자나 공백으로 입력해주세요. ";
                }
                if (String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).charAt(String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).length - 1) == 'V') {
                    ds_csv.setCellData(i, ds_csv.getColumnID(11), ds_csv.getCellData(i, ds_csv.getColumnID(10)) * 0.1);
                }
                break;
            case 12:
                if (temp == '' || isNaN(temp) || temp.length != 8) {
                    err += "'Result Date'열은 날짜로 입력해주세요. ";
                }
                else if (scwin.f_JobCloseYn(temp) == -1) {
                    err += "'Result Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
                }
                break;
            case 13:
                break;
            case 14:
                if (partnerYn == 'N' && (temp != '' && temp != 'Y')) {
                    err += "'외화 정산'열은 Y나 공백으로 입력해주세요. ";
                }
                break;
            case 15:
                break;
            case 16:
                if (temp == '') {
                    err += "'요청범위'를 입력해주세요. (1~2) ";
                }
                else if (temp != '1' && temp != '2') {
                    err += "'요청범위'는 1~2 사이의 숫자를 입력해주세요. ";
                } else if (temp == '2') {
                    if (ds_csv.getCellData(i, ds_csv.getColumnID(13)) == '' || isNaN(ds_csv.getCellData(i, ds_csv.getColumnID(13))) || String(ds_csv.getCellData(i, ds_csv.getColumnID(13))).length != 8) {
                        err += "'Invoice Date'열은 날짜로 입력해주세요. ";
                    }
                    else if (scwin.f_JobCloseYn(ds_csv.getCellData(i, ds_csv.getColumnID(13))) == -1) {
                        err += "'Invoice Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
                    }
                }
                break;
            }
        }

        ds_err.insertRow(ds_err.getRowCount());
        ds_err.setCellData(ds_err.getRowCount() - 1, "err", err);
        if (err == '') {
            ds_RetrieveValidation.removeAll();
            ds_validation.removeAll();
            // TODO: ImportData/ExportData 1행 복사 → WebSquare에서는 행 단위 복사 로직 필요
            ds_RetrieveValidation.insertRow(0);
            for (let col = 0; col < ds_csv.getColumnCount(); col++) {
                let colId = ds_csv.getColumnID(col);
                let csvColIds = ["seaAirCls","expImp","partner","cd","blNo","custCd","freightCd","crcCd","amount","exRate","amountWon","vat","resultDate","billingDate","foreignCurSet","innerDept","requestSize","err"];
                if (col < csvColIds.length) {
                    ds_RetrieveValidation.setCellData(0, csvColIds[col], ds_csv.getCellData(i, colId));
                }
            }
            await $c.sbm.execute(sbm_validation);
        }
    }

    let csvColIds = ["seaAirCls","expImp","partner","cd","blNo","custCd","freightCd","crcCd","amount","exRate","amountWon","vat","resultDate","billingDate","foreignCurSet","innerDept","requestSize","err"];
    ds_freightList.removeAll();
    for (let r = 0; r < cntRow; r++) {
        ds_freightList.insertRow(ds_freightList.getRowCount());
        for (let c = 0; c < ds_csv.getColumnCount(); c++) {
            if (c < csvColIds.length) {
                ds_freightList.setCellData(r, csvColIds[c], ds_csv.getCellData(r, ds_csv.getColumnID(c)));
            }
        }
    }
    for (let k = 0; k < ds_freightList.getRowCount(); k++) {
        ds_freightList.setCellData(k, "err", ds_err.getCellData(k, "err"));
    }
    ds_err.removeAll();
    return true;
};

scwin.drmFileSubmit = function() {
    $c.gus.cfDrmUploadFile(fileUploadGDS, "scwin.f_Upload");
};

scwin.f_Upload = function() {
    ds_csv.removeAll();
    // TODO: fileUploadGDS 기반 CSV 업로드 → WebSquare 파일 업로드 방식으로 대체 필요
    ds_csv.setDataId(fileUploadGDS.getCellData(0, "filePath"));
    $c.gus.cfProgressWinOpen();
    $p.setTimeout(function() { scwin.f_Import(); }, {"delay": 1000});
};

scwin.f_Import = async function() {
    scwin.f_DsClear();
    scwin.flag = false;
    $c.gus.cfProgressWinClose();
    if (await scwin.f_CsvValidation()) {
        $c.gus.cfShowTotalRows(totalRows, ds_freightList.getRowCount());
        await $c.gus.cfAlertMsg("업로드 완료");
    }
    else {
        $c.gus.cfShowTotalRows(totalRows, 0);
    }
    scwin.f_ErrCheck();
};

scwin.f_ErrCheck = function() {
    for (let i = 0; i < ds_freightList.getRowCount(); i++) {
        if (ds_freightList.getCellData(i, "err") != "") {
            scwin.flag = false;
            return;
        }
    }
    scwin.flag = true;
    return;
};

scwin.f_Save = async function() {
    if (scwin.editFlag) {
        await $c.gus.cfAlertMsg("수정한 값이 존재합니다. 재검증 버튼을 눌러 재검증을 해주세요.");
        return;
    }
    if (!ds_freightList.isUpdated()) {
        await $c.gus.cfAlertMsg("변경된 내역이 없습니다. 업로드 후 저장해주세요.");
        return;
    }
    if (!scwin.flag) {
        await $c.gus.cfAlertMsg("수정되지 않은 오류 내역이 있습니다. '오류'열을 확인하고, 수정 후 재업로드 해주세요.");
        return;
    }

    let chk = await $c.win.confirm("저장하시겠습니까?");
    if (!chk) {
        return;
    }

    for (let i = 0; i < ds_freightList.getRowCount(); i++) {
        ds_dbCodeRetrieve.removeAll();
        ds_dbCodeRetrieve.insertRow(0);
        let csvColIds = ["seaAirCls","expImp","partner","cd","blNo","custCd","freightCd","crcCd","amount","exRate","amountWon","vat","resultDate","billingDate","foreignCurSet","innerDept","requestSize","err"];
        for (let c = 0; c < csvColIds.length; c++) {
            ds_dbCodeRetrieve.setCellData(0, csvColIds[c], ds_freightList.getCellData(i, csvColIds[c]));
        }
        await $c.sbm.execute(sbm_dbCodeRetrieve);
    }

    for (let i = 0; i < ds_freightList.getRowCount(); i++) {
        let SA = ds_freightList.getCellData(i, "seaAirCls");
        let IE = ds_freightList.getCellData(i, "expImp");
        let P = "Y";

        let temp;
        let tempInv;
        if (SA == 'S') {
            if (IE == 'I') {
                if (P == 'Y') {
                    temp = ds_seaImpPartner;
                    tempInv = ds_invoiceSIP;
                }
                else {
                    temp = ds_seaImpBuying;
                    tempInv = ds_invoiceSIB;
                }
            }
            else {
                if (P == 'Y') {
                    temp = ds_seaExpPartner;
                    tempInv = ds_invoiceSEP;
                }
                else {
                    temp = ds_seaExpBuying;
                    tempInv = ds_invoiceSEB;
                }
            }
        }
        else {
            if (IE == 'I') {
                if (P == 'Y') {
                    temp = ds_airImpPartner;
                    tempInv = ds_invoiceAIP;
                }
                else {
                    temp = ds_airImpBuying;
                    tempInv = ds_invoiceAIB;
                }
            }
            else {
                if (P == 'Y') {
                    temp = ds_airExpPartner;
                    tempInv = ds_invoiceAEP;
                }
                else {
                    temp = ds_airExpBuying;
                    tempInv = ds_invoiceAEB;
                }
            }
        }

        let newRow = temp.insertRow(temp.getRowCount());
        let r = temp.getRowCount() - 1;
        temp.setCellData(r, "odrNo", ds_dbCodeList.getCellData(i, "odrNo"));
        temp.setCellData(r, "kcomcd", ds_dbCodeList.getCellData(i, "kcomcd"));
        temp.setCellData(r, "seaAirCls", SA);
        temp.setCellData(r, "blNo", ds_freightList.getCellData(i, "blNo"));
        temp.setCellData(r, "mhno", ds_dbCodeList.getCellData(i, "mhno"));
        temp.setCellData(r, "fareEngCd", ds_freightList.getCellData(i, "freightCd"));
        temp.setCellData(r, "fareEngNm", ds_dbCodeList.getCellData(i, "fareEngNm"));
        temp.setCellData(r, "fareGrpCd", ds_dbCodeList.getCellData(i, "fareGrpCd"));
        temp.setCellData(r, "fareUnit", SA == 'S' ? 'CASE' : '');
        temp.setCellData(r, "locPtnCls", '1');
        temp.setCellData(r, "mblHblCls", 'H');
        temp.setCellData(r, "drcrCls", 'D');
        temp.setCellData(r, "ppccCls", SA == 'S' ? ds_dbCodeList.getCellData(i, "ppccCls") : '');
        temp.setCellData(r, "crcCd", ds_freightList.getCellData(i, "crcCd"));
        temp.setCellData(r, "qty", SA == 'S' ? 0 : ds_dbCodeList.getCellData(i, "qty"));
        temp.setCellData(r, "grossWt", SA == 'S' ? 0.0 : ds_dbCodeList.getCellData(i, "grossWt"));
        temp.setCellData(r, "chgWt", 1);
        temp.setCellData(r, "trfUpr", 0.0);
        temp.setCellData(r, "exRate", ds_freightList.getCellData(i, "exRate"));
        temp.setCellData(r, "exRateTyp", SA == 'S' ? ds_dbCodeList.getCellData(i, "exRateTyp") : '');
        temp.setCellData(r, "prtnAmt", 0);
        temp.setCellData(r, "rsltsStdDt", ds_freightList.getCellData(i, "resultDate"));
        temp.setCellData(r, "vatYn", ds_freightList.getCellData(i, "vat") > 0 ? 1 : 0);

        temp.setCellData(r, "sellSeq", 0);
        temp.setCellData(r, "bilgClntNo", ds_freightList.getCellData(i, "custCd"));
        temp.setCellData(r, "bilgClntNm", ds_dbCodeList.getCellData(i, "bilgClntNm"));
        temp.setCellData(r, "sellItemCd", ds_dbCodeList.getCellData(i, "sellItemCd"));
        temp.setCellData(r, "sellUpr", 1);
        temp.setCellData(r, "sellAmtFcrc", ds_freightList.getCellData(i, "amount"));
        temp.setCellData(r, "sellAmt", ds_freightList.getCellData(i, "amountWon") != '' ?
                ds_freightList.getCellData(i, "amountWon") : (ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate")));
        temp.setCellData(r, "vatAmt", ds_freightList.getCellData(i, "vat"));

        if (SA == 'S' && ds_dbCodeList.getCellData(i, "usdAmt") != 0) {
            temp.setCellData(r, "usdAmt", P == 'Y' ?
                    Math.round((temp.getCellData(r, "sellAmt") / ds_dbCodeList.getCellData(i, "usdAmt")) * 100) / 100
                    : Math.round((temp.getCellData(r, "pchsAmt") / ds_dbCodeList.getCellData(i, "usdAmt")) * 100) / 100);
        }

        if (SA == 'A' && IE == 'E' && P == 'Y') {
            temp.setCellData(r, "qty", 0);
            temp.setCellData(r, "grossWt", 0);
        }

        let invRow = tempInv.insertRow(tempInv.getRowCount());
        let ir = tempInv.getRowCount() - 1;
        let tempColCount = temp.getColumnCount();
        for (let tc = 0; tc < tempColCount; tc++) {
            let colId = temp.getColumnID(tc);
            tempInv.setCellData(ir, colId, temp.getCellData(r, colId));
        }
        tempInv.setCellData(ir, "billingDate", ds_freightList.getCellData(i, "billingDate"));
        tempInv.setCellData(ir, "foreignCurSet", ds_freightList.getCellData(i, "foreignCurSet"));
        tempInv.setCellData(ir, "requestSize", ds_freightList.getCellData(i, "requestSize"));
        tempInv.setCellData(ir, "partner", P);
        tempInv.setCellData(ir, "expImp", IE == 'I' ? 'I' : 'O');
        if ("Y" != tempInv.getCellData(ir, "foreignCurSet")) {
            tempInv.setCellData(ir, "crcCd", "KRW");
        }
    }

    await $c.sbm.execute(sbm_saveFreight);
};

scwin.f_tmp = function() {
    let tmp = "확인 \n\n";
    let check = ds_seaImpPartner;
    for (let i = 0; i < check.getRowCount(); i++) {
        for (let j = 0; j < check.getColumnCount(); j++) {
            tmp = tmp + check.getCellData(i, check.getColumnID(j)) + ", ";
        }
        tmp = tmp + "\n";
    }
    alert(tmp);

    let cnt = "열 수 확인 \n" + ds_seaImpPartner.getRowCount() + "\n" + ds_seaImpBuying.getRowCount() + "\n"
    + ds_seaExpPartner.getRowCount() + "\n" + ds_seaExpBuying.getRowCount() + "\n"
    + ds_airImpPartner.getRowCount() + "\n" + ds_airImpBuying.getRowCount() + "\n"
    + ds_airExpPartner.getRowCount() + "\n" + ds_airExpBuying.getRowCount() + "\n";
    alert(cnt);
};

scwin.f_DsClear = function() {
    ds_freightList.removeAll();
    ds_RetrieveValidation.removeAll();
    ds_validation.removeAll();
    ds_err.removeAll();
    ds_seaImpPartner.removeAll();
    ds_seaImpBuying.removeAll();
    ds_seaExpPartner.removeAll();
    ds_seaExpBuying.removeAll();
    ds_airImpPartner.removeAll();
    ds_airImpBuying.removeAll();
    ds_airExpPartner.removeAll();
    ds_airExpBuying.removeAll();
    ds_dbCodeList.removeAll();
    ds_dbCodeRetrieve.removeAll();
    ds_dbCodeResult.removeAll();
    ds_invoiceSIP.removeAll();
    ds_invoiceSIB.removeAll();
    ds_invoiceSEP.removeAll();
    ds_invoiceSEB.removeAll();
    ds_invoiceAIP.removeAll();
    ds_invoiceAIB.removeAll();
    ds_invoiceAEP.removeAll();
    ds_invoiceAEB.removeAll();
    $c.gus.cfShowTotalRows(totalRows, 0);
};

scwin.f_ReCheck = async function() {
    if (!scwin.editFlag) {
        await $c.gus.cfAlertMsg("값을 수정 후, 재검증 버튼을 눌러주세요.");
        return;
    }
    if (ds_freightList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg("먼저 CSV 파일을 업로드해주세요.");
        return;
    }
    ds_csv.removeAll();
    let csvColIds = ["seaAirCls","expImp","partner","cd","blNo","custCd","freightCd","crcCd","amount","exRate","amountWon","vat","resultDate","billingDate","foreignCurSet","innerDept","requestSize","err"];
    for (let r = 0; r < ds_freightList.getRowCount(); r++) {
        ds_csv.insertRow(ds_csv.getRowCount());
        for (let c = 0; c < csvColIds.length; c++) {
            ds_csv.setCellData(r, ds_csv.getColumnID(c), ds_freightList.getCellData(r, csvColIds[c]));
        }
    }
    ds_freightList.removeAll();
    ds_err.removeAll();

    if (await scwin.f_CsvValidation()) {
        scwin.f_ErrCheck();
        await $c.gus.cfAlertMsg("재검사를 완료하였습니다.");
    }
    scwin.editFlag = false;
};

scwin.sbm_validation_submitdone = function(e) {
    let arr = ["blNo", "custCd", "freightCd", "crcCd", "innerDept"];
    let arrMsg = ["House B/L", "Customer Code", "Freight Code", "CUR Code", "내부거래 코드"];

    let msg = "";
    for (let i = 0; i < arr.length; i++) {
        if (ds_validation.getCellData(0, arr[i]) != '1') {
            msg += arrMsg[i] + " 항목이 유효하지 않습니다. ";
        }
    }
    ds_err.setCellData(ds_err.getRowCount() - 1, "err", ds_err.getCellData(ds_err.getRowCount() - 1, "err") + msg);
};

scwin.sbm_validation_submiterror = function(e) {
    $c.gus.cfShowError(e);
    scwin.f_DsClear();
    ds_csv.removeAll();
};

scwin.sbm_dbCodeRetrieve_submitdone = function(e) {
    ds_dbCodeList.insertRow(ds_dbCodeList.getRowCount());
    let r = ds_dbCodeList.getRowCount() - 1;
    ds_dbCodeList.setCellData(r, "kcomcd", ds_dbCodeResult.getCellData(0, "kcomcd"));
    ds_dbCodeList.setCellData(r, "blNo", ds_dbCodeResult.getCellData(0, "blNo"));
    ds_dbCodeList.setCellData(r, "mhno", ds_dbCodeResult.getCellData(0, "mhno"));
    ds_dbCodeList.setCellData(r, "ppccCls", ds_dbCodeResult.getCellData(0, "ppccCls"));
    ds_dbCodeList.setCellData(r, "odrNo", ds_dbCodeResult.getCellData(0, "odrNo"));
    ds_dbCodeList.setCellData(r, "usdAmt", ds_dbCodeResult.getCellData(0, "usdAmt"));
    ds_dbCodeList.setCellData(r, "exRateTyp", ds_dbCodeResult.getCellData(0, "exRateTyp"));
    ds_dbCodeList.setCellData(r, "fareEngNm", ds_dbCodeResult.getCellData(0, "fareEngNm"));
    ds_dbCodeList.setCellData(r, "sellItemCd", ds_dbCodeResult.getCellData(0, "sellItemCd"));
    ds_dbCodeList.setCellData(r, "fareGrpCd", ds_dbCodeResult.getCellData(0, "fareGrpCd"));
    ds_dbCodeList.setCellData(r, "bilgClntNm", ds_dbCodeResult.getCellData(0, "bilgClntNm"));
