};

scwin.sbm_saveFreight_submitdone = async function(e) {
    await $c.win.alert("저장이 완료되었습니다.");
    ds_freightList_complete.removeAll();
    let csvColIds = ["seaAirCls","expImp","partner","cd","blNo","custCd","freightCd","crcCd","amount","exRate","amountWon","vat","resultDate","billingDate","foreignCurSet","innerDept","requestSize","err"];
    for (let r = 0; r < ds_freightList.getRowCount(); r++) {
        ds_freightList_complete.insertRow(ds_freightList_complete.getRowCount());
        for (let c = 0; c < csvColIds.length; c++) {
            ds_freightList_complete.setCellData(r, csvColIds[c], ds_freightList.getCellData(r, csvColIds[c]));
        }
    }
    $c.gus.cfShowTotalRows(totalRows2, ds_freightList_complete.getRowCount());
    scwin.f_DsClear();
};

