    ds_invoiceSEP.removeAll();
    ds_invoiceSEB.removeAll();
    ds_invoiceAIP.removeAll();
    ds_invoiceAIB.removeAll();
    ds_invoiceAEP.removeAll();
    ds_invoiceAEB.removeAll();
};

scwin.gr_freightList_oneditend = function(rowIndex, columnId, oldValue, newValue) {
